mapper.select:
SELECT * FROM sys_user WHERE del_flag = '0'

    AND username LIKE CONCAT('%', #{username}, '%')


    AND nick_name LIKE CONCAT('%', #{nickName}, '%')


    AND status = #{status}


    AND phone = #{phone}

ORDER BY create_time DESC

SELECT r.id FROM sys_role r
LEFT JOIN sys_user_role ur ON ur.role_id = r.id
WHERE ur.user_id = #{userId}

mapper.insert:
INSERT INTO sys_user (
    username, password, nick_name, email, phone, sex, avatar, status,
    create_by, create_time, remark
) VALUES (
    #{username}, #{password}, #{nickName}, #{email}, #{phone}, #{sex}, #{avatar}, #{status},
    #{createBy}, NOW(), #{remark}
)

mapper.update:
UPDATE sys_user SET nick_name = #{nickName}, email = #{email}, phone = #{phone}, sex = #{sex}, status = #{status}, update_by = #{updateBy}, update_time = NOW()
, avatar = #{avatar}
, remark = #{remark}
WHERE id = #{id}
